import { useEffect } from 'react';
import { NameAndType } from '@pages/OrganizationApplication/NameAndType';
import { useNavigate } from 'react-router-dom';
import { useGetAccount } from '@state/accounts';
import { PageLayout } from '@ui/components/Layout/PageLayout';
import { getBasePaths } from '@ui/utils/getBasePaths';

const { basePath } = getBasePaths();

export const NewAccountApplication = () => {
  const navigate = useNavigate();
  const { currentAccount } = useGetAccount();

  useEffect(() => {
    if (currentAccount?.id) {
      navigate(`${basePath}/accounts/${currentAccount.id}/application`);
    }
  }, [currentAccount?.id, navigate]);

  if (!currentAccount) {
    return (
      <PageLayout>
        <NameAndType />
      </PageLayout>
    );
  }

  return null;
};

export default NewAccountApplication;
