/* eslint-disable @typescript-eslint/no-use-before-define */
import { useQueryClient } from 'react-query';
import { useGetAccount } from '@state/accounts';
import { generateQueryKey } from './keyFactory';

export function useCacheHelper(resourceKey: string, providedAccountId?: string) {
  const queryClient = useQueryClient();
  const { currentAccount } = useGetAccount();
  const accountId = providedAccountId || currentAccount?.id;

  const refreshCache = async (resourceId?: string) => {
    const queries = [];
    if (resourceId) {
      // Invalidate and refetch active single query in the background
      queries.push(
        queryClient.invalidateQueries({
          queryKey: generateQueryKey({ accountId, resourceId, resourceKey }),
        })
      );
      queries.push(
        queryClient.invalidateQueries({
          queryKey: generateQueryKey({ resourceId, resourceKey }),
        })
      );
      queries.push(
        queryClient.invalidateQueries({
          queryKey: generateQueryKey({
            resourceId,
            resourceKey,
            resourceType: 'entity',
          }),
        })
      );
    }
    // Invalidate and refetch active list queries in the background
    queries.push(
      queryClient.invalidateQueries({
        queryKey: generateQueryKey({ accountId, resourceKey }),
      })
    );

    // Invalidates queries which ignore the current account
    queries.push(
      queryClient.invalidateQueries({
        queryKey: generateQueryKey({ resourceKey }),
      })
    );

    await Promise.all(queries);
  };

  return {
    refreshCache,
  };
}
