import { useRouteConfig } from '@pages/useRouteConfig';
import { Helmet } from 'react-helmet-async';
import { matchRoutes, RouteObject, useLocation } from 'react-router-dom';
import { RouteOption } from '@domain/routeOption';
import { useGetAccount } from '@state/accounts';

export const PageTitle = () => {
  const { currentAccount } = useGetAccount();
  const location = useLocation();

  // routeConfig is an array of RouteOption (an extension of RouteObject)
  // matchRoutes doesn't care about the extra stuff and can't tell
  // that it's the right thing so we cast it here
  const routeConfig = useRouteConfig() as RouteObject[];

  const matchedRoutes = matchRoutes(routeConfig, location.pathname);
  const currentRoute = matchedRoutes
    ? (matchedRoutes[matchedRoutes.length - 1].route as RouteOption)
    : undefined;

  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  const fullTitle = [
    currentRoute ? currentRoute?.pageTitle : '',
    currentAccount?.displayName,
    'Anedot',
  ]
    .filter(Boolean)
    .join(' - ');

  return (
    <Helmet>
      <title>{fullTitle}</title>
    </Helmet>
  );
};
